body:
The following index example disables dynamic mappings at the root level
and uses static mappings to index the `relationships` field as the
`embeddedDocuments` type. It also applies the configured
`stringBooleanIndex` `typeSet` to index only the `string` and
`boolean` types the `relationships` array of objects. It applies the
`stringBooleanIndex` `typeSet` to the nested `person` document to
index only the `boolean` and `string` types in the `person`
document.

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_training").Collection("companies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the Atlas Search index for the embeddedDocuments field with dynamic mapping
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"relationships", bson.D{
						{"type", "embeddedDocuments"},
						{"dynamic", bson.D{
							{"typeSet", "stringBooleanIndex"},
						}},
						{"fields", bson.D{
							{"person", bson.D{
								{"type", "document"},
								{"dynamic", bson.D{
									{"typeSet", "stringBooleanIndex"},
								}},
							}},
						}},
					}},
				}},
			}},
			{"typeSets", bson.A{
				bson.D{
					{"name", "stringBooleanIndex"},
					{"types", bson.A{
						bson.D{{"type", "boolean"}},
						bson.D{{"type", "string"}},
					}},
				},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}

